const categories = ["Office","Business","Career","Education","Personal Goals","Daily Life","Technical","Predictions"];
const difficulties = ["easy","medium","hard"];

// Generate derived questions
const generated = [];
let idCounter = allBasePairs.length + 1;

// Generate systematic combinations
for (let t = 0; t < timeExpressions.length; t++) {
  for (let v = 0; v < verbPairs.length; v++) {
    const time = timeExpressions[t];
    const vp = verbPairs[v];
    // Use subject "I" variation
    const cat = categories[(t * verbPairs.length + v) % categories.length];
    const diff = difficulties[(t + v) % 3];
    generated.push({
      h: `${time.h}, मैंने ${vp.obj_h} ${vp.h} ।`,
      e: `${time.e}, I ${vp.e} ${vp.obj_e}.`,
      cat,
      diff,
      tags: ["future-perfect"]
    });
    // "they" variation
    generated.push({
      h: `${time.h}, उन्होंने ${vp.obj_h} ${vp.h} ।`,
      e: `${time.e}, they ${vp.e} ${vp.obj_e}.`,
      cat,
      diff,
      tags: ["future-perfect"]
    });
  }
}

// Also add "will not have" versions for some
for (let t = 0; t < 8; t++) {
  for (let v = 0; v < 10; v++) {
    const time = timeExpressions[t];
    const vp = verbPairs[v];
    generated.push({
      h: `${time.h}, मैंने ${vp.obj_h} नहीं ${vp.h} ।`,
      e: `${time.e}, I won't have ${vp.v3} ${vp.obj_e}.`,
      cat: "Negative",
      diff: "medium",
      tags: ["negative","future-perfect"]
    });
  }
}

// Question forms
for (let t = 0; t < 6; t++) {
  for (let v = 0; v < 8; v++) {
    const time = timeExpressions[t];
    const vp = verbPairs[v];
    generated.push({
      h: `क्या तुमने ${time.h} ${vp.obj_h} ${vp.h} ?`,
      e: `Will you have ${vp.v3} ${vp.obj_e} ${time.e.replace('By ','by ').replace('In ','in ')}?`,
      cat: "Questions",
      diff: "medium",
      tags: ["question","future-perfect"]
    });
  }
}

const allPairs = [...allBasePairs, ...generated];

// Build questions array, deduplicate by english sentence, cap at 950
const seen = new Set();
const questions = [];
for (let i = 0; i < allPairs.length && questions.length < 950; i++) {
  const p = allPairs[i];
  const key = p.e.trim().toLowerCase();
  if (seen.has(key)) continue;
  seen.add(key);
  const id = questions.length + 1;
  const grammarRule = p.tags.includes("passive")
    ? "By + [time] + subject + will have been + V3"
    : p.tags.includes("negative")
    ? "Subject + won't have + V3"
    : p.tags.includes("question")
    ? "Will + subject + have + V3?"
    : "Subject + will have + V3";
  questions.push({
    id,
    hindi: p.h,
    english: p.e,
    alternatives: [],
    hint: grammarRule,
    explanation: `Future Perfect tense: ${grammarRule}`,
    difficulty: p.diff || "medium",
    tags: p.tags || ["future-perfect"],
    grammarRule,
    category: p.cat || "Future Perfect"
  });
}

// Pad to 950 if needed using more verb/time combos with "she/he/team"
const moreSubjects = [
  {h_pronoun:"वह (पुरुष)", e_pronoun:"he", h_verb_suffix:"होगा"},
  {h_pronoun:"वह (महिला)", e_pronoun:"she", h_verb_suffix:"होगी"},
  {h_pronoun:"team", e_pronoun:"the team", h_verb_suffix:"होगी"},
  {h_pronoun:"manager", e_pronoun:"the manager", h_verb_suffix:"होगा"},
];

let padId = questions.length;
outer:
for (let s = 0; s < moreSubjects.length; s++) {
  for (let t = 0; t < timeExpressions.length; t++) {
    for (let v = 0; v < verbPairs.length; v++) {
      if (questions.length >= 950) break outer;
      const sub = moreSubjects[s];
      const time = timeExpressions[t];
      const vp = verbPairs[v];
      const e = `${time.e}, ${sub.e_pronoun} ${vp.e} ${vp.obj_e}.`;
      const key = e.trim().toLowerCase();
      if (seen.has(key)) continue;
      seen.add(key);
      padId++;
      questions.push({
        id: padId,
        hindi: `${time.h}, ${sub.h_pronoun} ने ${vp.obj_h} ${vp.h} ।`,
        english: e,
        alternatives: [],
        hint: "Subject + will have + V3",
        explanation: "Future Perfect tense: Subject + will have + V3",
        difficulty: difficulties[(s+t+v)%3],
        tags: ["future-perfect"],
        grammarRule: "Subject + will have + V3",
        category: categories[(s*t+v) % categories.length]
      });
    }
  }
}

const pqOut = {
  totalQuestions: questions.length,
  topic: "Will Have (Future Perfect)",
  day: 8,
  instructions: "नीचे दिए गए Hindi sentences को English में translate करें।",
  questions
};

