// Convert paddingWords arrays into full word objects
function makePaddingObj(arr) {
  return {
    word: arr[0], hindi: arr[1], simpleMeaning: arr[2], ipa: arr[3],
    base: arr[4], s3: arr[5], ing: arr[6], past: arr[7], pp: arr[8],
    syn: arr[9], ant: arr[10],
    daily: arr[11], office: arr[12], interview: arr[13], business: arr[14],
    formal: arr[15], informal: arr[16],
    note: arr[17], cefr: arr[18]
  };
}

const paddingObjs = paddingWords.map(makePaddingObj);
const allVocabAll = [...allVocabCombined, ...paddingObjs];

function buildWordEntry(src, id) {
  return {
    id,
    word: src.word,
    hindi: src.hindi,
    simpleMeaning: src.simpleMeaning,
    ipa: src.ipa,
    verbForms: {
      base: src.base || "-",
      s3: src.s3 || "-",
      ing: src.ing || "-",
      past: src.past || "-",
      pastParticiple: src.pp || "-"
    },
    synonyms: src.syn || [],
    antonyms: src.ant || [],
    sentences: {
      daily: src.daily || "-",
      office: src.office || "-",
      interview: src.interview || "-",
      business: src.business || "-",
      formal: src.formal || "-",
      informal: src.informal || "-"
    },
    usageNote: src.note || "-",
    cefrLevel: src.cefr || "B1"
  };
}

// Build deduped vocab list
const vocabSeenSet = new Set();
const finalVocab = [];
for (const w of allVocabAll) {
  const key = w.word.toLowerCase().trim();
  if (vocabSeenSet.has(key)) continue;
  vocabSeenSet.add(key);
  finalVocab.push(buildWordEntry(w, finalVocab.length + 1));
  if (finalVocab.length >= 950) break;
}

